import{_ as o,o as t,c as r,a2 as i}from"./chunks/framework.Bix3-HpO.js";const u=JSON.parse('{"title":"Theme Customizer","description":"FXT Theme Customizer","frontmatter":{"title":"Theme Customizer","description":"FXT Theme Customizer","weight":110,"extra":{"order":110},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/fxt/theme-customizer"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/fxt/theme-customizer"}],["meta",{"property":"og:title","content":"Theme Customizer"}],["meta",{"property":"og:description","content":"FXT Theme Customizer"}],["meta",{"name":"twitter:title","content":"Theme Customizer"}],["meta",{"name":"twitter:description","content":"FXT Theme Customizer"}]]},"headers":[],"relativePath":"docs/fxt/theme-customizer.md","filePath":"docs/fxt/theme-customizer.md"}'),a={name:"docs/fxt/theme-customizer.md"};function l(s,e,n,c,h,m){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="theme-customizer" tabindex="-1">Theme Customizer <a class="header-anchor" href="#theme-customizer" aria-label="Permalink to &quot;Theme Customizer&quot;">​</a></h1><p>FXT theme provides extensive customization options through the WordPress Customizer, allowing you to modify colors, styles, and appearance without editing code.</p><hr><h2 id="accessing-the-customizer" tabindex="-1">Accessing the Customizer <a class="header-anchor" href="#accessing-the-customizer" aria-label="Permalink to &quot;Accessing the Customizer&quot;">​</a></h2><p>To access the theme customizer:</p><ol><li>In WordPress dashboard, go to <strong>Appearance</strong> → <strong>Customize</strong></li><li>The customizer will open with a live preview of your website</li><li>Use the left sidebar to navigate through different sections</li></ol><hr><h2 id="fxt-styles-panel" tabindex="-1">FXT Styles Panel <a class="header-anchor" href="#fxt-styles-panel" aria-label="Permalink to &quot;FXT Styles Panel&quot;">​</a></h2><p>The <strong>FXT Styles</strong> panel contains all theme-specific customization options.</p><h3 id="theme-colors" tabindex="-1">Theme Colors <a class="header-anchor" href="#theme-colors" aria-label="Permalink to &quot;Theme Colors&quot;">​</a></h3><p>Customize the main color scheme of your website.</p><p><strong>Available Colors</strong>:</p><ul><li>Body Text Color: Main text color throughout the site</li><li>Background Color: Main background color</li><li>Button Color: Primary button background color</li><li>Review Links Color: Color for review and rating links</li></ul><h3 id="header-colors" tabindex="-1">Header Colors <a class="header-anchor" href="#header-colors" aria-label="Permalink to &quot;Header Colors&quot;">​</a></h3><p>Customize header-specific colors and styling.</p><p><strong>Available Colors</strong>:</p><ul><li>Header Background Color: Main header background</li><li>Header Text Color: Header text and navigation color</li><li>Header Link Color: Header navigation link color</li><li>Header Link Hover Color: Header link hover state</li></ul><h3 id="footer-colors" tabindex="-1">Footer Colors <a class="header-anchor" href="#footer-colors" aria-label="Permalink to &quot;Footer Colors&quot;">​</a></h3><p>Customize footer-specific colors and styling.</p><p><strong>Available Colors</strong>:</p><ul><li>Footer Background Color: Main footer background</li><li>Footer Text Color: Footer text color</li><li>Footer Link Color: Footer link color</li><li>Footer Link Hover Color: Footer link hover state</li></ul><hr><h2 id="live-preview" tabindex="-1">Live Preview <a class="header-anchor" href="#live-preview" aria-label="Permalink to &quot;Live Preview&quot;">​</a></h2><p>All changes made in the customizer are displayed in real-time in the preview panel:</p><ol><li>Make changes in the left sidebar</li><li>See immediate updates in the preview</li><li>Changes are not published until you click <strong>Publish</strong></li></ol><hr><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><p><a href="/docs/fxt/demo-import">Demo Import</a></p>',28)])])}const p=o(a,[["render",l]]);export{u as __pageData,p as default};
